1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface QuoteItem {
6	  type: string;
7	}
8	
9	export interface QuoteStep {
10	  op: "quote";
11	  items: QuoteItem[];
12	}
13	
14	export type Step = QuoteStep;
15	
16	export interface Scenario {
17	  customer: Customer;
18	  steps: Step[];
19	}
20	
21	export interface QuoteResult {
22	  premium: number;
23	}
24	
25	export type StepResult = QuoteResult;
26	
27	export interface ScenarioResult {
28	  results: StepResult[];
29	}
30	
31	const basePremiums: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const PROCESSING_FEE = 5;
41	
42	const BLOCK_OF_THREE_BASE = 60;
43	
44	const isBlockOfThree = (items: QuoteItem[]): boolean =>
45	  items.length === 3 && items.every((item) => item.type === items[0].type);
46	
47	const sumOfBasePremiums = (items: QuoteItem[]): number =>
48	  items.reduce((sum, item) => sum + basePremiums[item.type], 0);
49	
50	export function runScenario(scenario: Scenario): ScenarioResult {
51	  const results = scenario.steps.map((step) => {
52	    const basePremium = isBlockOfThree(step.items)
53	      ? BLOCK_OF_THREE_BASE
54	      : sumOfBasePremiums(step.items);
55	    return { premium: basePremium + PROCESSING_FEE };
56	  });
57	  return { results };
58	}
